def plot_series(steps, mean_vals, std_vals, label, color):
    plt.plot(steps, mean_vals, label=label, color=color, linewidth=2)
    plt.fill_between(steps, mean_vals - std_vals, mean_vals + std_vals, color=color, alpha=0.15)

